require "util.VideoAdHelper"
require "config.Define"

CustomListener = {}

function CustomListener:init()
    WatchAdvertFinishedEvent.registerCallBack(self.onWatchAdvertFinished)
    CommonDataEvents:registerCallBack("ClickWatchRespawnAd", function(userId)
        local player = PlayerManager:getPlayerByUserId(userId)
        if player == nil then
            GameMatch:ifGameOverByPlayer()
            return
        end
        RespawnManager:removeSchedule(player.userId) ---删除之前的死亡复活检测
        RespawnManager:addSchedule(player.userId, 80) ---看广告80秒，80秒后没回来就算没看，可以去死
    end)
end

function CustomListener.onWatchAdvertFinished(rakssid, type, params, code)
    local player = PlayerManager:getPlayerByRakssid(rakssid)
    if player == nil then
        return
    end
    if code == 1 then
        if type == Define.AdType.RespawnAd then
            VideoAdHelper:doRespawnVideoAdReward(player)
        end
    else
        player:onDie()
        GameMatch:ifGameOverByPlayer()
    end
end
return CustomListener